class Solution(object):
    def binaryTreePaths(self, root):
        result = []
        def dfs(node, path):
            if not node:
                return
            path += str(node.val)
            if not node.left and not node.right:
                result.append(path)
            else:
                dfs(node.left, path + '->')
                dfs(node.right, path + '->')
        dfs(root, '')
        return result
